public static void Main(Args _args)
{
    Dialog Dialog = new Dialog("SQL");

    DialogField queryInput = dialog.addField( extendedTypeStr(Notes), "SQL query");
    DialogField infoOnly   = dialog.addField(extendedTypeStr(NoYesId), "Info only");
    DialogField excelOutput   = dialog.addField(extendedTypeStr(NoYesId), "Excel Output");

    excelOutput.value(true);

    Dialog.run();

    if(Dialog.closedOk() && queryInput.value() )
    {
        str query = queryInput.value();
        boolean isInfoOnly = infoOnly.value();
        boolean isExcelOutput = excelOutput.value();

        DatabaseQueryHelper::process(query, isInfoOnly,isExcelOutput);


    }
}
